import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Scanner;

public class SecurePathTraversal {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a file name: ");
        String fileName = scanner.nextLine();

        // Construct the full path using Paths.get() to avoid path traversal
        Path filePath = Paths.get("/path/to/directory", fileName).toAbsolutePath().normalize();

        if (filePath.startsWith(Paths.get("/path/to/directory"))) {
            if (Files.exists(filePath)) {
                System.out.println("File exists!");
                // Perform some operation with the file
            } else {
                System.out.println("File does not exist!");
            }
        } else {
            System.out.println("Invalid file path!");
        }
    }
}

